sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
/* ===============================
   MAIN LAYOUT
=============================== */
.all-connections-wrapper {
  display: flex;
  align-items: flex-start;
  max-height: calc(100vh - 64px);
  position: relative;
}

/* Sidebar */
.dm-sidebar-slot {
  width: 250px;
  flex-shrink: 0;
}

/* Right content column */
.content-area {
  flex: 1;
  padding: 10px 30px 30px 30px;
  max-height: calc(100vh - 64px);
  position: relative;
  overflow-y:auto;
}

/* ===============================
   HEADER FIX
=============================== */
.page-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 12px;
  gap: 20px;
}

.header-left p {
  margin-bottom: 0;
}

.page-header h2 {
  font-size: 28px;
  font-weight: 600;
  margin-bottom: 6px;
}

.page-header p {
  color: #6b7280;
  margin-bottom: 16px;
  max-width: 420px;
}


/* ===============================
   TABLE CARD
=============================== */
.table-card {
  background: #fff;
  border-radius: 14px;
  padding: 20px;
  box-shadow: 0 12px 30px rgba(0,0,0,0.06);
}

/* Table */
.dm-table {
  width: 100%;
  border-collapse: collapse;
}

.dm-table th {
  text-align: left;
  padding: 12px;
  background: #f3f4f6;
  font-weight: 600;
  border-bottom: 1px solid #e5e7eb;
}

.dm-table td {
  padding: 14px 12px;
  border-bottom: 1px solid #f1f3f6;
}

.dm-table tr:hover {
  background: #f9fafb;
}

/* Badges */
.status-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 14px;
  border-radius: 999px;
  font-size: 13px;
  font-weight: 600;
}

.status-badge i {
  font-size: 13px;
}

.status-success {
  background: #d1fae5;
  color: #047857;
}

.status-partial {
  background: #fdecc8;
  color: #b45309;
}

.status-error {
  background: #fee2e2;
  color: #b91c1c;
}

.tblback {
  color:#4764D3;
}

/* ===============================
   RESPONSIVE
=============================== */
@media (max-width: 900px) {
  .all-connections-wrapper {
    flex-direction: column;
  }

  .dm-sidebar-slot {
    width: 100%;
  }
}

sp_widget.script:
(function() {
  data.side = $sp.getWidget('dmm_sidebar');
  data.connections = [];

  var gr = new GlideRecord('x_sysus_data_mig_0_migration_details');
  gr.orderByDesc('sys_created_on');
  gr.addQuery('sys_created_by', gs.getUserName());
  gr.query();

  while (gr.next()) {

		var tablesArr = [];

var tablesStr = gr.getValue('table') || "";

tablesArr.push()
    data.connections.push({
      sys_id: gr.getUniqueValue(),
      number: gr.getValue('number'), // ✅ fixed typo
      tables: Object.keys(JSON.parse(tablesStr)), // ✅ array for badges
      records: gr.getValue('records_inserted') || '0', // ✅ added records
      state: gr.getValue('state'),
      duration: gr.getValue('duration'),
      created: gr.getDisplayValue('sys_created_on'),

			successRate: parseInt(gr.getValue('success_rate')) || 0
    });
  }

})();
